const headers = ($json && typeof $json === 'object' && $json.headers && typeof $json.headers === 'object') ? $json.headers : {};
const body = ($json && typeof $json === 'object') ? ($json.body ?? $json) : {};

const getHeader = (name) => {
  const target = String(name).toLowerCase();
  for (const [k, v] of Object.entries(headers)) {
    if (String(k).toLowerCase() === target) return v;
  }
  return undefined;
};

const expectedSecret = $env.TVG_STATE_SECRET;
if (!expectedSecret || String(expectedSecret).trim() === '') {
  return [{ json: { status:'error', error_type:'config_missing', message:'Missing env var TVG_STATE_SECRET', details:'', error_http_code:500 } }];
}

const incomingSecret = getHeader('X-State-Secret');
if (!incomingSecret || String(incomingSecret).trim() === '' || String(incomingSecret) !== String(expectedSecret)) {
  return [{ json: { status:'error', error_type:'auth_failed', message:'Missing or invalid X-State-Secret', details:'', error_http_code:401 } }];
}

if (!body || typeof body !== 'object' || Array.isArray(body)) {
  return [{ json: { status:'error', error_type:'validation_failed', message:'Payload must be a JSON object', details:'Invalid payload shape', error_http_code:400 } }];
}

const asString = (v) => (typeof v === 'string' ? v.trim() : (v === null || v === undefined ? '' : String(v).trim()));
const asStringList = (v) => Array.isArray(v) ? v.map(asString).filter(Boolean).slice(0, 60) : null;

const lastUpdated = asString(body.last_updated);
const completed = asStringList(body.completed);
const inProgress = asStringList(body.in_progress);
const nextStep = asStringList(body.next_step);

const missing = [];
if (!completed) missing.push('completed');
if (!inProgress) missing.push('in_progress');
if (!nextStep) missing.push('next_step');

if (missing.length) {
  return [{ json: { status:'error', error_type:'validation_failed', message:'Missing/invalid required fields', details: JSON.stringify({ missing_fields: missing }), error_http_code:400 } }];
}

const todayIso = new Date().toISOString().slice(0, 10);
const effectiveDate = lastUpdated && /^\d{4}-\d{2}-\d{2}$/.test(lastUpdated) ? lastUpdated : todayIso;

const renderList = (items) => items.length ? items.map(i => `- ${i}`).join('\n') : '-';

const stateMd = [
  `Last Updated: ${effectiveDate}`,
  '',
  '## Completed',
  renderList(completed),
  '',
  '## In Progress',
  renderList(inProgress),
  '',
  '## Next Step',
  renderList(nextStep),
  '',
].join('\n');

const rootFolderId = $env.TVG_SYSTEM_ROOT_FOLDER_ID;
if (!rootFolderId || String(rootFolderId).trim() === '') {
  return [{ json: { status:'error', error_type:'config_missing', message:'Missing env var TVG_SYSTEM_ROOT_FOLDER_ID', details:'', error_http_code:500 } }];
}

return [{ json: { status:'pass', state_md: stateMd, drive_root_folder_id: String(rootFolderId).trim(), command_center_folder_name:'Command-Center', pilot_reports_folder_name:'Pilot-Reports', state_file_name:'state.md' } }];

const ctx = $items('Validate + Build State')[0]?.json;
const items = $input.all().map(i => i.json);
const errItem = items.find(j => j && typeof j === 'object' && j.error);
if (errItem) {
  return [{ json: { status:'error', error_type:'drive_failed', message:'Drive folder search failed', details: JSON.stringify(errItem), error_http_code:502 } }];
}
const folders = items.filter(j => j && typeof j === 'object' && typeof j.id === 'string' && j.id && j.name === ctx.command_center_folder_name);
if (folders.length > 1) return [{ json: { status:'error', error_type:'drive_failed', message:'Multiple Command-Center folders found; cannot proceed safely', details: JSON.stringify({ folder_ids: folders.map(f => f.id) }), error_http_code:502 } }];
if (folders.length === 1) return [{ json: { status:'found', command_center_folder_id: folders[0].id } }];
return [{ json: { status:'create', command_center_folder_name: ctx.command_center_folder_name, drive_root_folder_id: ctx.drive_root_folder_id } }];

const created = $json;
if (created && typeof created === 'object' && created.error) {
  return [{ json: { status:'error', error_type:'drive_failed', message:'Failed to create Command-Center folder', details: JSON.stringify({ message: created.error.message, name: created.error.name }), error_http_code:502 } }];
}
if (!created || typeof created.id !== 'string' || !created.id) {
  return [{ json: { status:'error', error_type:'drive_failed', message:'Drive did not return folder id for Command-Center', details:'', error_http_code:502 } }];
}
return [{ json: { status:'pass', command_center_folder_id: created.id } }];

const ctx = $items('Validate + Build State')[0]?.json;
const items = $input.all().map(i => i.json);
const errItem = items.find(j => j && typeof j === 'object' && j.error);
if (errItem) {
  return [{ json: { status:'error', error_type:'drive_failed', message:'Drive state.md search failed', details: JSON.stringify(errItem), error_http_code:502 } }];
}
const found = items.filter(j => j && typeof j === 'object' && typeof j.id === 'string' && j.id && j.name === ctx.state_file_name);
if (found.length > 1) return [{ json: { status:'error', error_type:'drive_failed', message:'Multiple state.md files found; cannot proceed safely', details: JSON.stringify({ file_ids: found.map(f => f.id) }), error_http_code:502 } }];
if (found.length === 1) return [{ json: { status:'update', state_file_id: found[0].id } }];
return [{ json: { status:'create' } }];

const created = $json;
if (created && typeof created === 'object' && created.error) {
  return [{ json: { status:'error', error_type:'drive_failed', message:'Drive state.md write failed', details: JSON.stringify({ message: created.error.message, name: created.error.name }), error_http_code:502 } }];
}
if (!created || typeof created.id !== 'string' || !created.id) {
  return [{ json: { status:'error', error_type:'drive_failed', message:'Drive did not return file id for state.md', details:'', error_http_code:502 } }];
}
return [{ json: { status:'pass', state_file_id: created.id } }];
